# Two Sum - Python
import json

nums = json.loads(input())
target = int(input())

def two_sum(nums, target):
    lookup = {}
    for i, num in enumerate(nums):
        if target - num in lookup:
            return [lookup[target - num], i]
        lookup[num] = i
    return []

print(two_sum(nums, target))

